/// Encrypts plaintext with ChaCha20Poly1305 using given key and nonce.
pub fn encrypt(
    key: &[u8; 32],
    nonce: &Nonce,
    plaintext: &[u8],
    aad: &[u8],
) -> Result<Vec<u8>, &'static str> {
    let cipher = ChaCha20Poly1305::new(key.into());
    let mut buffer = plaintext.to_vec();
    cipher
        .encrypt_in_place(nonce, aad, &mut buffer)
        .map_err(|_| "Encryption failed")?;
    Ok(buffer)
}

/// Decrypts ciphertext with ChaCha20Poly1305.
pub fn decrypt(
    key: &[u8; 32],
    nonce: &Nonce,
    ciphertext: &[u8],
    aad: &[u8],
) -> Result<Vec<u8>, &'static str> {
    let cipher = ChaCha20Poly1305::new(key.into());
    let mut buffer = ciphertext.to_vec();
    cipher
        .decrypt_in_place(nonce, aad, &mut buffer)
        .map_err(|_| "Decryption failed")?;
    Ok(buffer)
}

/// Verifies an Ed25519 signature against a message and a public key.
pub fn verify_signature(
    public_key: &PublicKey,
    message: &[u8],
    signature: &SignatureBytes,
) -> Result<(), SignatureError> {
    let ed_signature = EdSignature::from_slice(signature.as_slice())?;
    public_key.verify(&hash_sha3_256(message), &ed_signature)
}
